inbound.set-body:
@{
            var req = context.Request.Body.As<JObject>();
            var qsName = req["quantitySpecification"] != null ? (string)req["quantitySpecification"] : "All";
            int qs;
            switch (qsName)
            {
                case "ReservedPhysically": qs = 1; break;
                case "ReservedPhysicallyAndCrossDock": qs = 2; break;
                default: qs = 0; break;
            }
            bool allowPartial = req["allowPartiallyReleased"] != null && (bool)req["allowPartiallyReleased"];
            bool groupMultiple = req["groupIntoMultipleReleases"] != null && (bool)req["groupIntoMultipleReleases"];
            string packedQuery = req["packedQuery"] != null ? (string)req["packedQuery"] : "";
            var contract = new JObject(
                new JProperty("WHSReleaseQuantitySpecification", qs),
                new JProperty("AllowPartiallyReleased", allowPartial ? 1 : 0),
                new JProperty("GroupIntoMultipleReleases", groupMultiple ? 1 : 0),
                new JProperty("_packedQuery", packedQuery)
            );
            return new JObject(new JProperty("_contract", contract)).ToString();
        }
